  1	import {
  2	  BreadcrumbItem,
  3	  Text,
  4	  TextVariants,
  5	  Tooltip,
  6	} from '@patternfly/react-core';
  7	import { Link } from 'react-router-dom-v5-compat';
  8	import * as React from 'react';
  9	import { useParams } from 'react-router-dom-v5-compat';
 10	import { ArchiveIcon } from '@patternfly/react-icons';
 11	import { ResourceStatus } from '@openshift-console/dynamic-plugin-sdk';
 12	import DetailsPage from '../../details-page/DetailsPage';
 13	import { getReferenceForModel } from '../../pipelines-overview/utils';
 14	import { TaskRunModel } from '../../../models';
 15	import { useTranslation } from 'react-i18next';
 16	import TaskRunDetails from './TaskRunDetails';
 17	import TaskRunLogsTab from './TaskRunLogsTab';
 18	import TaskRunEvents from './events/TaskRunEvents';
 19	import { useTaskRun } from '../../hooks/useTaskRuns';
 20	import { navFactory } from '../../utils/horizontal-nav';
 21	import ResourceYAMLEditorViewOnly from '../../yaml-editor/ResourceYAMLEditorViewOnly';
 22	import {
 23	  DELETED_RESOURCE_IN_K8S_ANNOTATION,
 24	  RESOURCE_LOADED_FROM_RESULTS_ANNOTATION,
 25	} from '../../../consts';
 26	import { LoadingBox } from '../../status/status-box';
 27	import { taskRunStatus } from '../../utils/pipeline-utils';
 28	import Status from '../../status/Status';
 29	
 30	const TaskRunDetailsPage = () => {
 31	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 32	  const params = useParams();
 33	  const { name, ns: namespace } = params;
 34	  const [data, loaded] = useTaskRun(namespace, name);
 35	  const trStatus = React.useMemo(
 36	    () => loaded && data && taskRunStatus(data),
 37	    [loaded, data],
 38	  );
 39	  const resourceTitleFunc = React.useMemo(() => {
 40	    return (
 41	      <div className="taskrun-details-page">
 42	        {data?.metadata?.name}{' '}
 43	        {(data?.metadata?.annotations?.[DELETED_RESOURCE_IN_K8S_ANNOTATION] ===
 44	          'true' ||
 45	          data?.metadata?.annotations?.[
 46	            RESOURCE_LOADED_FROM_RESULTS_ANNOTATION
 47	          ] === 'true') && (
 48	          <Tooltip content={t('Archived in Tekton results')}>
 49	            <ArchiveIcon className="pipelinerun-details-page__results-indicator" />
 50	          </Tooltip>
 51	        )}
 52	        <ResourceStatus>
 53	          <Status status={trStatus}></Status>
 54	        </ResourceStatus>
 55	      </div>
 56	    );
 57	  }, [data]);
 58	
 59	  if (!loaded) {
 60	    return <LoadingBox />;
 61	  }
 62	  return (
 63	    <DetailsPage
 64	      obj={data}
 65	      headTitle={name}
 66	      title={<Text component={TextVariants.h1}>{resourceTitleFunc}</Text>}
 67	      baseURL={`/tasks/ns/${namespace}/${getReferenceForModel(
 68	        TaskRunModel,
 69	      )}/${name}/task-runs`}
 70	      model={TaskRunModel}
 71	      breadcrumbs={[
 72	        <BreadcrumbItem key="app-link" component="div">
 73	          <Link
 74	            data-test="breadcrumb-link"
 75	            className="pf-v6-c-breadcrumb__link"
 76	            to={`/tasks/ns/${namespace}/task-runs`}
 77	          >
 78	            {t('TaskRuns')}
 79	          </Link>
 80	        </BreadcrumbItem>,
 81	        {
 82	          path: `/tasks/ns/${namespace}/task-runs`,
 83	          name: t('TaskRun details'),
 84	        },
 85	      ]}
 86	      pages={[
 87	        navFactory.details(TaskRunDetails),
 88	        navFactory.editYaml(ResourceYAMLEditorViewOnly),
 89	        {
 90	          href: 'logs',
 91	          path: 'logs/:name?',
 92	          name: t('Logs'),
 93	          component: TaskRunLogsTab,
 94	        },
 95	        navFactory.events(TaskRunEvents),
 96	      ]}
 97	    />
 98	  );
 99	};
100	
101	export default TaskRunDetailsPage;

